executeJS.function:
var input = document.evaluate(
    "{{inputSelector}}",
    document,
    null,
    XPathResult.FIRST_ORDERED_NODE_TYPE,
    null
).singleNodeValue;
var datepicker = document.querySelector("{{datePickerWidgetSelector}}");

if (!input) {
    return 'Date input field not found';
}
if (!datepicker) {
    return 'Datepicker widget not found';
}

var inputRect = input.getBoundingClientRect();
var datepickerRect = datepicker.getBoundingClientRect();

var horizontalAligned = Math.abs(datepickerRect.left - inputRect.left) < 80;
var verticalNear = datepickerRect.top >= inputRect.top - 10
    && datepickerRect.top <= inputRect.bottom + 320;
var fullyVisible = datepickerRect.top >= 0
    && datepickerRect.left >= 0
    && datepickerRect.bottom <= window.innerHeight
    && datepickerRect.right <= window.innerWidth;

return (horizontalAligned && verticalNear && fullyVisible)
    ? 'Datepicker is correctly positioned relative to input'
    : 'Datepicker is mispositioned relative to input';
